"use client"

import { X } from "lucide-react"
import Image from "next/image"
import { useChatInput } from "../../ChatInputContext"

/**
 * Horizontal scrolling attachment previews
 * Shows at top of composer (grid-area: header)
 */
export function AttachmentPills() {
  const { attachments, removeAttachment } = useChatInput()

  if (attachments.length === 0) return null

  return (
    <div className="-mx-2.5 -mt-2.5 mb-2.5 flex flex-col [grid-area:header]">
      <div className="w-full">
        <div className="no-scrollbar horizontal-scroll-fade-mask flex flex-nowrap gap-2 overflow-x-auto px-2.5 pt-2.5 pb-1.5 [--edge-fade-distance:1rem]">
          {attachments.map(attachment => (
            <div key={attachment.id} className="group text-token-text-primary relative inline-block text-sm">
              {/* Attachment preview */}
              <div className="border-token-border-default bg-primary relative overflow-hidden border rounded-2xl">
                <div className="h-14.5 w-14.5">
                  {attachment.type === "image" && attachment.preview ? (
                    <div className="relative w-full h-full bg-gray-500 dark:bg-gray-700">
                      <Image src={attachment.preview} alt={attachment.file.name} fill className="object-cover" />
                    </div>
                  ) : (
                    <div className="flex items-center h-full w-full justify-center bg-gray-500 dark:bg-gray-700 text-white">
                      <span className="text-xs font-medium">
                        {attachment.file.name.split(".").pop()?.toUpperCase()}
                      </span>
                    </div>
                  )}
                </div>
              </div>

              {/* Remove button */}
              <div className="absolute end-1.5 top-1.5 inline-flex gap-1">
                <button
                  type="button"
                  onClick={() => removeAttachment(attachment.id)}
                  className="transition-colors flex h-4 w-4 items-center justify-center rounded-full border-[rgba(0,0,0,0.1)] bg-black text-white dark:border-[rgba(255,255,255,0.1)] dark:bg-white dark:text-black hover:scale-110"
                  aria-label="Remove file"
                >
                  <X className="size-3" strokeWidth={3} />
                </button>
              </div>

              {/* Upload progress */}
              {attachment.uploadProgress !== undefined && attachment.uploadProgress < 100 && (
                <div className="absolute bottom-0 left-0 right-0 h-1 bg-black/10 dark:bg-white/10 rounded-b overflow-hidden">
                  <div
                    className="h-full bg-gradient-to-r from-blue-500 to-blue-600 transition-all duration-300"
                    style={{ width: `${attachment.uploadProgress}%` }}
                  />
                </div>
              )}
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}
