"use client"

import { AlertCircle } from "lucide-react"
import { useChatInput } from "../ChatInputContext"

export function ErrorMessage() {
  const { error } = useChatInput()

  if (!error) return null

  return (
    <div className="mx-3 mt-2 flex items-start gap-2 px-3 py-2 rounded-lg bg-red-50 dark:bg-red-950/20 border border-red-200 dark:border-red-800">
      <AlertCircle className="size-4 text-red-600 dark:text-red-400 mt-0.5 flex-shrink-0" />
      <p className="text-sm text-red-700 dark:text-red-300 flex-1">{error}</p>
    </div>
  )
}
