"use client"

import * as DropdownMenu from "@radix-ui/react-dropdown-menu"
import { Camera, Paperclip, Plus } from "lucide-react"
import type { RefObject } from "react"
import { useChatInput } from "../../ChatInputContext"

interface PlusMenuProps {
  fileInputRef: RefObject<HTMLInputElement>
}

/**
 * Plus button with dropdown menu
 * Grid area: leading
 */
export function PlusMenu({ fileInputRef }: PlusMenuProps) {
  const { openCamera, config } = useChatInput()

  return (
    <div className="[grid-area:leading]">
      <span className="flex" data-state="closed">
        <DropdownMenu.Root>
          <DropdownMenu.Trigger asChild>
            <button
              type="button"
              className="composer-btn flex items-center justify-center w-9 h-9 rounded-full hover:bg-black/5 dark:hover:bg-white/5 transition-colors text-black/60 dark:text-white/60 hover:text-black dark:hover:text-white"
              data-testid="composer-plus-btn"
              aria-label="Add files and more"
            >
              <Plus className="size-5" strokeWidth={2} />
            </button>
          </DropdownMenu.Trigger>

          <DropdownMenu.Portal>
            <DropdownMenu.Content
              className="min-w-[220px] bg-white dark:bg-gray-800 rounded-xl shadow-lg border border-black/10 dark:border-white/10 p-1.5"
              sideOffset={8}
              align="start"
            >
              {config.enableAttachments && (
                <DropdownMenu.Item
                  className="flex items-center gap-3 px-3 py-2.5 rounded-lg hover:bg-black/5 dark:hover:bg-white/5 cursor-pointer outline-none text-sm text-black dark:text-white"
                  onSelect={() => fileInputRef.current?.click()}
                >
                  <Paperclip className="size-4" />
                  <span>Upload files</span>
                </DropdownMenu.Item>
              )}

              {config.enableCamera && (
                <DropdownMenu.Item
                  className="flex items-center gap-3 px-3 py-2.5 rounded-lg hover:bg-black/5 dark:hover:bg-white/5 cursor-pointer outline-none text-sm text-black dark:text-white"
                  onSelect={openCamera}
                >
                  <Camera className="size-4" />
                  <span>Take photo</span>
                </DropdownMenu.Item>
              )}
            </DropdownMenu.Content>
          </DropdownMenu.Portal>
        </DropdownMenu.Root>
      </span>
    </div>
  )
}
