"use client"

import { useCallback, useEffect, useMemo, useState } from "react"
import { ChatInputProvider } from "./ChatInputContext"
import { AttachFileButton } from "./components/AttachFileButton"
import { Attachments } from "./components/Attachments"
import { CameraButton } from "./components/CameraButton"
import { CameraModal } from "./components/CameraModal"
import { ErrorMessage } from "./components/ErrorMessage"
import { InputArea } from "./components/InputArea"
import { SendButton } from "./components/SendButton"
import { Toolbar } from "./components/Toolbar"
import { useAttachments } from "./hooks/useAttachments"
import { useImageCapture } from "./hooks/useImageCapture"
import type { ChatInputConfig, ChatInputContextValue, ChatInputProps } from "./types"

function ChatInputRoot({
  message,
  setMessage,
  busy,
  abortControllerRef,
  onSubmit,
  onStop,
  config: userConfig = {},
  children,
}: ChatInputProps) {
  const [isDragging, setIsDragging] = useState(false)
  const [error, setError] = useState<string | undefined>()

  // Merge with default config
  const config: ChatInputConfig = useMemo(
    () => ({
      enableAttachments: true,
      enableCamera: false,
      maxAttachments: 10,
      maxFileSize: 10 * 1024 * 1024,
      placeholder: "Tell me what to change...",
      minHeight: "80px",
      maxHeight: "200px",
      onMessage: (msg, type) => {
        if (type === "error") {
          setError(msg)
          setTimeout(() => setError(undefined), 5000)
        }
      },
      ...userConfig,
    }),
    [userConfig],
  )

  // Hooks
  const { attachments, addAttachment, removeAttachment } = useAttachments(config)

  const handlePhotoCapture = useCallback(
    (blob: Blob) => {
      const file = new File([blob], `photo-${Date.now()}.jpg`, { type: "image/jpeg" })
      addAttachment(file)
    },
    [addAttachment],
  )

  const { isCameraOpen, openCamera, closeCamera, capturePhoto } = useImageCapture(handlePhotoCapture)

  // Validation
  const canSubmit = useMemo(() => {
    if (busy) return false
    const hasMessage = message.trim().length > 0
    const hasAttachments = attachments.length > 0
    const attachmentsValid = attachments.every(a => !a.error && a.uploadProgress === 100)
    return (hasMessage || hasAttachments) && attachmentsValid
  }, [busy, message, attachments])

  // Keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Cmd/Ctrl + K to focus input
      if ((e.metaKey || e.ctrlKey) && e.key === "k") {
        e.preventDefault()
        const textarea = document.querySelector('[data-testid="message-input"]') as HTMLTextAreaElement
        textarea?.focus()
      }
    }

    window.addEventListener("keydown", handleKeyDown)
    return () => window.removeEventListener("keydown", handleKeyDown)
  }, [])

  // Context value
  const contextValue: ChatInputContextValue = useMemo(
    () => ({
      message,
      setMessage,
      attachments,
      addAttachment,
      removeAttachment,
      isCameraOpen,
      openCamera,
      closeCamera,
      capturePhoto,
      isDragging,
      setIsDragging,
      busy,
      abortControllerRef,
      canSubmit,
      error,
      onSubmit,
      onStop,
      config,
    }),
    [
      message,
      setMessage,
      attachments,
      addAttachment,
      removeAttachment,
      isCameraOpen,
      openCamera,
      closeCamera,
      capturePhoto,
      isDragging,
      busy,
      abortControllerRef,
      canSubmit,
      error,
      onSubmit,
      onStop,
      config,
    ],
  )

  // Drag & drop handlers
  const handleDragEnter = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
    setIsDragging(true)
  }, [])

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
    if (e.currentTarget === e.target) {
      setIsDragging(false)
    }
  }, [])

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
  }, [])

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault()
      e.stopPropagation()
      setIsDragging(false)

      const files = Array.from(e.dataTransfer.files)
      for (const file of files) {
        addAttachment(file)
      }
    },
    [addAttachment],
  )

  // Paste handler for images
  const handlePaste = useCallback(
    (e: React.ClipboardEvent) => {
      const items = Array.from(e.clipboardData.items)
      for (const item of items) {
        if (item.type.startsWith("image/")) {
          const file = item.getAsFile()
          if (file) {
            addAttachment(file)
          }
        }
      }
    },
    [addAttachment],
  )

  return (
    <ChatInputProvider value={contextValue}>
      <section
        className="flex-shrink-0 p-4 safe-area-inset-bottom"
        aria-label="Chat input with file drop"
        onDragEnter={handleDragEnter}
        onDragLeave={handleDragLeave}
        onDragOver={handleDragOver}
        onDrop={handleDrop}
        onPaste={handlePaste}
      >
        <div
          className={`relative border ${
            isDragging ? "border-blue-500 bg-blue-50 dark:bg-blue-950/20" : "border-black/20 dark:border-white/20"
          } focus-within:border-black/40 dark:focus-within:border-white/40 transition-colors`}
        >
          {/* Drag overlay */}
          {isDragging && (
            <div className="absolute inset-0 z-50 flex flex-col items-center justify-center gap-3 bg-blue-500/10 backdrop-blur-sm rounded">
              <div className="w-16 h-16 rounded-full bg-blue-500/20 flex items-center justify-center">
                <svg
                  className="w-8 h-8 text-blue-600 dark:text-blue-400"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"
                  />
                </svg>
              </div>
              <p className="text-sm font-medium text-blue-600 dark:text-blue-400">Drop files to attach</p>
              <p className="text-xs text-blue-500 dark:text-blue-500">Images and documents supported</p>
            </div>
          )}

          {/* Error message */}
          <ErrorMessage />

          {/* Attachments preview */}
          <Attachments />

          {/* Input area */}
          {children}
        </div>

        {/* Camera modal */}
        <CameraModal />
      </section>
    </ChatInputProvider>
  )
}

// Compound component pattern
export const ChatInput = Object.assign(ChatInputRoot, {
  InputArea,
  Toolbar,
  AttachFileButton,
  CameraButton,
  Attachments,
  SendButton,
  ErrorMessage,
})
