"use client"

import { Camera, X } from "lucide-react"
import { useCallback, useEffect, useRef, useState } from "react"
import { useChatInput } from "../ChatInputContext"

export function CameraModal() {
  const { isCameraOpen, closeCamera, capturePhoto } = useChatInput()
  const videoRef = useRef<HTMLVideoElement>(null)
  const streamRef = useRef<MediaStream | null>(null)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (!isCameraOpen) return

    async function startCamera() {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({
          video: { facingMode: "user", width: 1280, height: 720 },
        })
        streamRef.current = stream
        if (videoRef.current) {
          videoRef.current.srcObject = stream
        }
      } catch (err) {
        setError("Failed to access camera. Please check permissions.")
        console.error("Camera error:", err)
      }
    }

    startCamera()

    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop())
        streamRef.current = null
      }
    }
  }, [isCameraOpen])

  const handleCapture = useCallback(() => {
    if (!videoRef.current) return

    const canvas = document.createElement("canvas")
    canvas.width = videoRef.current.videoWidth
    canvas.height = videoRef.current.videoHeight
    const ctx = canvas.getContext("2d")
    if (!ctx) return

    ctx.drawImage(videoRef.current, 0, 0)
    canvas.toBlob(
      blob => {
        if (blob) {
          capturePhoto(blob)
        }
      },
      "image/jpeg",
      0.9,
    )
  }, [capturePhoto])

  if (!isCameraOpen) return null

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm">
      <div className="relative bg-white dark:bg-gray-900 rounded-lg shadow-xl max-w-2xl w-full mx-4">
        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b border-black/10 dark:border-white/10">
          <h3 className="text-lg font-medium text-black dark:text-white">Take Photo</h3>
          <button
            type="button"
            onClick={closeCamera}
            className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-black/5 dark:hover:bg-white/5 text-black/60 dark:text-white/60 transition-colors"
            aria-label="Close camera"
          >
            <X className="size-5" />
          </button>
        </div>

        {/* Video/Error */}
        <div className="relative aspect-video bg-black">
          {error ? (
            <div className="absolute inset-0 flex items-center justify-center text-white text-sm">{error}</div>
          ) : (
            <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" />
          )}
        </div>

        {/* Controls */}
        {!error && (
          <div className="flex items-center justify-center p-6">
            <button
              type="button"
              onClick={handleCapture}
              className="flex items-center gap-2 px-6 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors font-medium"
            >
              <Camera className="size-5" />
              Capture
            </button>
          </div>
        )}
      </div>
    </div>
  )
}
