"use client"

import { useCallback, useEffect, useMemo, useRef, useState } from "react"
import { ChatInputProvider } from "./ChatInputContext"
import { CameraModal } from "./components/CameraModal"
import { AttachmentPills } from "./components/v2/AttachmentPills"
import { ComposerGrid } from "./components/v2/ComposerGrid"
import { PlusMenu } from "./components/v2/PlusMenu"
import { PrimaryInput } from "./components/v2/PrimaryInput"
import { TrailingActions } from "./components/v2/TrailingActions"
import { useAttachments } from "./hooks/useAttachments"
import { useImageCapture } from "./hooks/useImageCapture"
import type { ChatInputConfig, ChatInputContextValue, ChatInputProps } from "./types"

/**
 * ChatInput V2 - Inspired by ChatGPT's composer architecture
 *
 * Key features:
 * - CSS Grid layout with named areas (header/leading/primary/trailing/footer)
 * - Radix UI primitives for accessibility
 * - Data attributes for state management
 * - Composer pills for active features
 * - Expandable/collapsible states
 */
export function ChatInputV2({
  message,
  setMessage,
  busy,
  abortControllerRef,
  onSubmit,
  onStop,
  config: userConfig = {},
}: Omit<ChatInputProps, "children">) {
  const [isDragging, setIsDragging] = useState(false)
  const [error, setError] = useState<string | undefined>()
  const [isExpanded, setIsExpanded] = useState(false)
  const fileInputRef = useRef<HTMLInputElement>(null)

  // Merge config
  const config: ChatInputConfig = useMemo(
    () => ({
      enableAttachments: true,
      enableCamera: false,
      maxAttachments: 10,
      maxFileSize: 10 * 1024 * 1024,
      placeholder: "Ask anything",
      minHeight: "56px", // min-h-14
      maxHeight: "30svh",
      onMessage: (msg, type) => {
        if (type === "error") {
          setError(msg)
          setTimeout(() => setError(undefined), 5000)
        }
      },
      ...userConfig,
    }),
    [userConfig],
  )

  // Hooks
  const { attachments, addAttachment, removeAttachment } = useAttachments(config)

  const handlePhotoCapture = useCallback(
    (blob: Blob) => {
      const file = new File([blob], `photo-${Date.now()}.jpg`, { type: "image/jpeg" })
      addAttachment(file)
    },
    [addAttachment],
  )

  const { isCameraOpen, openCamera, closeCamera, capturePhoto } = useImageCapture(handlePhotoCapture)

  // Validation
  const canSubmit = useMemo(() => {
    if (busy) return false
    const hasMessage = message.trim().length > 0
    const hasAttachments = attachments.length > 0
    const attachmentsValid = attachments.every(a => !a.error && a.uploadProgress === 100)
    return (hasMessage || hasAttachments) && attachmentsValid
  }, [busy, message, attachments])

  // Auto-expand when attachments added
  useEffect(() => {
    if (attachments.length > 0) {
      setIsExpanded(true)
    }
  }, [attachments.length])

  // Keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === "k") {
        e.preventDefault()
        const textarea = document.querySelector('[data-prompt-input="true"]') as HTMLTextAreaElement
        textarea?.focus()
      }
    }

    window.addEventListener("keydown", handleKeyDown)
    return () => window.removeEventListener("keydown", handleKeyDown)
  }, [])

  // Context value
  const contextValue: ChatInputContextValue = useMemo(
    () => ({
      message,
      setMessage,
      attachments,
      addAttachment,
      removeAttachment,
      isCameraOpen,
      openCamera,
      closeCamera,
      capturePhoto,
      isDragging,
      setIsDragging,
      busy,
      abortControllerRef,
      canSubmit,
      error,
      onSubmit,
      onStop,
      config,
    }),
    [
      message,
      setMessage,
      attachments,
      addAttachment,
      removeAttachment,
      isCameraOpen,
      openCamera,
      closeCamera,
      capturePhoto,
      isDragging,
      busy,
      abortControllerRef,
      canSubmit,
      error,
      onSubmit,
      onStop,
      config,
    ],
  )

  // Drag & drop handlers
  const handleDragEnter = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
    setIsDragging(true)
  }, [])

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
    if (e.currentTarget === e.target) {
      setIsDragging(false)
    }
  }, [])

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
  }, [])

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault()
      e.stopPropagation()
      setIsDragging(false)

      const files = Array.from(e.dataTransfer.files)
      for (const file of files) {
        addAttachment(file)
      }
    },
    [addAttachment],
  )

  const handlePaste = useCallback(
    (e: React.ClipboardEvent) => {
      const items = Array.from(e.clipboardData.items)
      for (const item of items) {
        if (item.type.startsWith("image/")) {
          const file = item.getAsFile()
          if (file) {
            addAttachment(file)
          }
        }
      }
    },
    [addAttachment],
  )

  return (
    <ChatInputProvider value={contextValue}>
      {/* Hidden file inputs */}
      <input
        ref={fileInputRef}
        type="file"
        multiple
        accept={config.allowedFileTypes?.join(",") || "image/*,.pdf,.txt,.md"}
        onChange={e => {
          const files = Array.from(e.target.files || [])
          for (const file of files) {
            addAttachment(file)
          }
          if (fileInputRef.current) fileInputRef.current.value = ""
        }}
        className="sr-only"
        tabIndex={-1}
        aria-hidden="true"
        id="composer-file-upload"
      />

      {/* Main composer */}
      <form
        className="group/composer w-full"
        data-expanded={isExpanded ? "" : undefined}
        data-dragging={isDragging ? "" : undefined}
        onSubmit={e => {
          e.preventDefault()
          if (canSubmit) onSubmit()
        }}
        onDragEnter={handleDragEnter}
        onDragLeave={handleDragLeave}
        onDragOver={handleDragOver}
        onDrop={handleDrop}
        onPaste={handlePaste}
      >
        <ComposerGrid isExpanded={isExpanded} isDragging={isDragging}>
          {/* Header: Attachment pills */}
          <AttachmentPills />

          {/* Leading: Plus menu */}
          <PlusMenu fileInputRef={fileInputRef} />

          {/* Primary: Text input */}
          <PrimaryInput />

          {/* Trailing: Voice + Send */}
          <TrailingActions />

          {/* Footer: Feature pills */}
          <div className="[grid-area:footer] flex items-center gap-1.5 px-2.5 pb-1.5">
            {/* Feature pills can go here */}
          </div>
        </ComposerGrid>
      </form>

      {/* Camera modal */}
      <CameraModal />
    </ChatInputProvider>
  )
}
