"use client"

import type { ReactNode } from "react"

interface ComposerGridProps {
  children: ReactNode
  isExpanded: boolean
  isDragging: boolean
}

/**
 * CSS Grid container with named areas
 *
 * Layout structure:
 * - header: attachment pills (top row)
 * - leading: plus button (left)
 * - primary: text input (center)
 * - trailing: voice + send buttons (right)
 * - footer: feature pills (bottom)
 *
 * Responsive:
 * - Collapsed: [leading | primary | trailing] in one row
 * - Expanded: [primary] takes full width, buttons move to footer row
 */
export function ComposerGrid({ children, isExpanded, isDragging }: ComposerGridProps) {
  return (
    <div
      className="bg-token-bg-primary cursor-text overflow-clip bg-clip-padding p-2.5 contain-inline-size dark:bg-[#303030] grid grid-cols-[auto_1fr_auto] [grid-template-areas:'header_header_header'_'leading_primary_trailing'_'._footer_.'] group-data-[expanded]/composer:[grid-template-areas:'header_header_header'_'primary_primary_primary'_'leading_footer_trailing'] shadow-[0_0_0_1px_rgba(0,0,0,0.08),0_2px_4px_rgba(0,0,0,0.05)] dark:shadow-[0_0_0_1px_rgba(255,255,255,0.08),0_2px_4px_rgba(0,0,0,0.3)] transition-shadow"
      style={{
        borderRadius: "28px",
      }}
      data-dragging={isDragging ? "" : undefined}
    >
      {/* Drag overlay */}
      {isDragging && (
        <div className="absolute inset-0 z-50 flex flex-col items-center justify-center gap-3 bg-blue-500/10 backdrop-blur-sm rounded-[28px]">
          <div className="w-16 h-16 rounded-full bg-blue-500/20 flex items-center justify-center">
            <svg
              className="w-8 h-8 text-blue-600 dark:text-blue-400"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"
              />
            </svg>
          </div>
          <p className="text-sm font-medium text-blue-600 dark:text-blue-400">Drop files to attach</p>
          <p className="text-xs text-blue-500">Images and documents supported</p>
        </div>
      )}

      {children}
    </div>
  )
}
