"use client"

import { useEffect, useRef } from "react"
import { useChatInput } from "../../ChatInputContext"

/**
 * Main text input area
 * Grid area: primary
 */
export function PrimaryInput() {
  const { message, setMessage, onSubmit, config } = useChatInput()
  const textareaRef = useRef<HTMLTextAreaElement>(null)

  // Auto-resize
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = "auto"
      const newHeight = Math.min(textareaRef.current.scrollHeight, 240) // max 240px
      textareaRef.current.style.height = `${newHeight}px`
    }
  }, [message])

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault()
      onSubmit()
    }
  }

  return (
    <div className="-my-2.5 flex min-h-14 items-center overflow-x-hidden px-1.5 [grid-area:primary] group-data-[expanded]/composer:mb-0 group-data-[expanded]/composer:px-2.5">
      <div className="_prosemirror-parent text-token-text-primary max-h-[max(30svh,5rem)] max-h-52 flex-1 overflow-auto [scrollbar-width:thin] vertical-scroll-fade-mask">
        <textarea
          ref={textareaRef}
          value={message}
          onChange={e => setMessage(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder={config.placeholder || "Ask anything"}
          className="w-full resize-none border-0 bg-transparent text-base font-normal focus:outline-none text-black dark:text-white placeholder:text-black/40 dark:placeholder:text-white/40"
          style={{
            minHeight: config.minHeight || "56px",
            maxHeight: config.maxHeight || "30svh",
          }}
          data-prompt-input="true"
          data-virtualkeyboard="true"
          aria-label={config.placeholder || "Message input"}
        />
      </div>
    </div>
  )
}
